#!/usr/bin/env node
/**
 * CLI script to deploy a Falcon-512 account on Starknet devnet.
 *
 * Bypasses the webapp entirely for faster debugging of the Cairo/RPC workflow.
 *
 * Usage: node apps/demo/scripts/deploy-falcon.mjs
 */

import { createRequire } from "module"
import { RpcProvider, Account, hash, stark, CallData, SignerInterface, transaction, EDAMode } from "../node_modules/starknet/dist/index.mjs"

// Load the Node.js WASM package (CJS)
const require = createRequire(import.meta.url)
const falcon = require("/home/felt/PycharmProjects/falcon-rs/pkg/falcon_rs.js")

// --- Config ---
const RPC_URL = "http://localhost:5050/rpc"
const CLASS_HASH = "0x37c7626b50ba517835c9556b53bce57cb6633704bb702f8c2f13a44cf151d5"

const provider = new RpcProvider({ nodeUrl: RPC_URL })

// --- Helpers ---

/** Deserialize 896-byte VK into 512 NTT-domain Int32Array coefficients */
function parsePublicKeyNtt(vkBytes) {
  const Q = 12289, N = 512, BITS = 14
  const coeffs = new Int32Array(N)
  const mask = (1 << BITS) - 1
  let bitBuffer = 0, bitsInBuffer = 0, byteIndex = 0
  for (let i = 0; i < N; i++) {
    while (bitsInBuffer < BITS) {
      bitBuffer |= vkBytes[byteIndex++] << bitsInBuffer
      bitsInBuffer += 8
    }
    const coeff = bitBuffer & mask
    bitBuffer >>= BITS
    bitsInBuffer -= BITS
    if (coeff >= Q) throw new Error(`Invalid VK coeff ${coeff} at ${i}`)
    coeffs[i] = coeff
  }
  return coeffs
}

/** Convert Int32Array to Uint16Array for pack_public_key_wasm */
function toUint16(int32Arr) {
  const u16 = new Uint16Array(int32Arr.length)
  for (let i = 0; i < int32Arr.length; i++) u16[i] = int32Arr[i]
  return u16
}

/** Fund an address via devnet JSON-RPC mint */
async function mintFunds(address, amount, unit) {
  const baseUrl = RPC_URL.replace(/\/rpc.*$/, "")
  const resp = await fetch(baseUrl, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      jsonrpc: "2.0",
      id: 1,
      method: "devnet_mint",
      params: { address, amount, unit },
    }),
  })
  if (!resp.ok) throw new Error(`Mint failed: ${resp.status} ${await resp.text()}`)
  const json = await resp.json()
  if (json.error) throw new Error(`Mint error: ${JSON.stringify(json.error)}`)
  return json.result
}

/** Get STRK balance of an address */
async function getBalance(address) {
  const STRK = "0x04718f5a0fc34cc1af16a1cdee98ffb20c31f5cd61d6ab07201858f4287c938d"
  const result = await provider.callContract({
    contractAddress: STRK,
    entrypoint: "balanceOf",
    calldata: [address],
  })
  return BigInt(result[0])
}

// --- FalconSigner (minimal, no Effect dependency) ---

class FalconSignerCLI extends SignerInterface {
  constructor(sk, pkNtt) {
    super()
    this.sk = sk
    this.pkNtt = pkNtt
  }

  async getPubKey() { return "0x0" }

  async signMessage() { throw new Error("signMessage not implemented") }

  async signTransaction(transactions, details) {
    const compiledCalldata = transaction.getExecuteCalldata(
      transactions,
      details.cairoVersion,
    )
    const txHash = hash.calculateInvokeTransactionHash({
      ...details,
      senderAddress: details.walletAddress,
      compiledCalldata,
      version: details.version,
      nonceDataAvailabilityMode: details.nonceDataAvailabilityMode === "L1" ? EDAMode.L1 : EDAMode.L2,
      feeDataAvailabilityMode: details.feeDataAvailabilityMode === "L1" ? EDAMode.L1 : EDAMode.L2,
    })
    return this._signHash(txHash)
  }

  async signDeployAccountTransaction(details) {
    const compiledConstructorCalldata = CallData.compile(details.constructorCalldata)
    const txHash = hash.calculateDeployAccountTransactionHash({
      ...details,
      salt: details.addressSalt,
      compiledConstructorCalldata,
      version: details.version,
      nonceDataAvailabilityMode: details.nonceDataAvailabilityMode === "L1" ? EDAMode.L1 : EDAMode.L2,
      feeDataAvailabilityMode: details.feeDataAvailabilityMode === "L1" ? EDAMode.L1 : EDAMode.L2,
    })
    return this._signHash(txHash)
  }

  async signDeclareTransaction() { throw new Error("signDeclareTransaction not implemented") }

  _signHash(txHash) {
    console.log(`  [Signer] Signing txHash: ${txHash}`)
    const sig = falcon.sign_for_starknet(this.sk, txHash, this.pkNtt)
    console.log(`  [Signer] Signature length: ${sig.length}`)
    // Unpack sig[0] (first packed s1 slot) to verify encoding
    const Q = 12289n
    const slot0 = BigInt(sig[0])
    const low = slot0 & ((1n << 128n) - 1n)
    const high = slot0 >> 128n
    let val = low
    const coeffs = []
    for (let i = 0; i < 9; i++) { coeffs.push(Number(val % Q)); val /= Q; }
    val = high
    for (let i = 0; i < 9; i++) { coeffs.push(Number(val % Q)); val /= Q; }
    console.log(`  [Signer] Unpacked s1[0..5] from sig[0]: [${coeffs.slice(0,5).join(', ')}]`)
    console.log(`  [Signer] sig[29] (salt_len): ${sig[29]}`)
    console.log(`  [Signer] sig[30] (salt[0]):  ${sig[30]}`)
    console.log(`  [Signer] sig[31] (salt[1]):  ${sig[31]}`)
    return sig
  }
}

// --- Main ---

async function main() {
  console.log("=== Falcon-512 Account Deploy (CLI) ===\n")
  console.log(`RPC: ${RPC_URL}`)
  console.log(`ClassHash: ${CLASS_HASH}\n`)

  // 1. Generate keypair
  console.log("--- Step 1: Generate Falcon-512 keypair ---")
  const seed = new Uint8Array(32)
  // Use a fixed seed for reproducibility
  for (let i = 0; i < 32; i++) seed[i] = i + 1
  const { sk, vk } = falcon.keygen(seed)
  console.log(`  SK: ${sk.length} bytes`)
  console.log(`  VK: ${vk.length} bytes`)

  // 2. Parse & NTT-transform & pack public key
  console.log("\n--- Step 2: Parse, NTT, and pack public key ---")
  const pkTime = parsePublicKeyNtt(vk) // time-domain coefficients (misleading name)
  console.log(`  pkTime: ${pkTime.length} coefficients, first 5: [${Array.from(pkTime.slice(0, 5)).join(", ")}]`)
  // Transform to NTT domain — required for both Cairo verification and hint generation
  const pkNtt = new Int32Array(falcon.ntt_public_key(pkTime))
  console.log(`  pkNtt:  ${pkNtt.length} coefficients, first 5: [${Array.from(pkNtt.slice(0, 5)).join(", ")}]`)
  const pkU16 = toUint16(pkNtt)
  const packedSlots = falcon.pack_public_key_wasm(pkU16)
  console.log(`  Packed: ${packedSlots.length} felt252 slots`)
  console.log(`  First slot: ${packedSlots[0]}`)
  console.log(`  Last slot:  ${packedSlots[packedSlots.length - 1]}`)

  // 3. Compute deploy address
  console.log("\n--- Step 3: Compute deploy address ---")
  const constructorCalldata = [...packedSlots]
  const salt = stark.randomAddress()
  const address = hash.calculateContractAddressFromHash(salt, CLASS_HASH, constructorCalldata, 0)
  console.log(`  Salt: ${salt}`)
  console.log(`  Address: ${address}`)

  // 4. Fund the address
  console.log("\n--- Step 4: Fund the address ---")
  const strkMint = await mintFunds(address, 10000000000000000000, "FRI")
  console.log(`  STRK mint: ${JSON.stringify(strkMint)}`)

  const balance = await getBalance(address)
  console.log(`  Balance: ${balance} (${Number(balance) / 1e18} STRK)`)

  // 5. Deploy account
  console.log("\n--- Step 5: Deploy account ---")
  const signer = new FalconSignerCLI(sk, pkNtt)
  const account = new Account({ provider, address, signer })

  try {
    const result = await account.deployAccount(
      {
        classHash: CLASS_HASH,
        constructorCalldata,
        addressSalt: salt,
        contractAddress: address,
      },
      {
        resourceBounds: {
          l2_gas: { max_amount: 0x2FAF080n, max_price_per_unit: 0x174876E800n },
          l1_gas: { max_amount: 0x0n, max_price_per_unit: 0x174876E800n },
          l1_data_gas: { max_amount: 0x3000n, max_price_per_unit: 0x174876E800n },
        },
      },
    )
    console.log(`  Deploy tx: ${result.transaction_hash}`)
    console.log(`  Contract address: ${result.contract_address}`)

    console.log("  Waiting for tx...")
    await provider.waitForTransaction(result.transaction_hash)
    console.log("  TX CONFIRMED!")
  } catch (error) {
    console.error("\n  DEPLOY FAILED:", error.message || error)
    if (error.message?.includes("TRANSACTION_EXECUTION_ERROR")) {
      // Extract and print the execution error details
      const match = error.message.match(/execution_error[\":\s]*(.*)/i)
      if (match) console.error("  Execution error:", match[1].slice(0, 500))
    }
    process.exit(1)
  }

  console.log("\n=== DEPLOY SUCCEEDED ===")

  // 6. Send STRK from deployed account
  console.log("\n--- Step 6: Send STRK transfer ---")
  const STRK_TOKEN = "0x04718f5a0fc34cc1af16a1cdee98ffb20c31f5cd61d6ab07201858f4287c938d"
  const recipient = "0x064b48806902a367c8598f4f95c305e8c1a1acba5f082d294a43793113115691" // devnet account #0
  const transferAmount = 1000000000000000n // 0.001 STRK

  try {
    const txResult = await account.execute(
      [
        {
          contractAddress: STRK_TOKEN,
          entrypoint: "transfer",
          calldata: CallData.compile({ recipient, amount: { low: transferAmount, high: 0n } }),
        },
      ],
      {
        resourceBounds: {
          l2_gas: { max_amount: 0x2FAF080n, max_price_per_unit: 0x174876E800n },
          l1_gas: { max_amount: 0x0n, max_price_per_unit: 0x174876E800n },
          l1_data_gas: { max_amount: 0x3000n, max_price_per_unit: 0x174876E800n },
        },
      },
    )
    console.log(`  Transfer tx: ${txResult.transaction_hash}`)
    console.log("  Waiting for tx...")
    await provider.waitForTransaction(txResult.transaction_hash)
    console.log("  TRANSFER CONFIRMED!")

    const balanceAfter = await getBalance(address)
    console.log(`  Balance after: ${balanceAfter} (${Number(balanceAfter) / 1e18} STRK)`)
  } catch (error) {
    console.error("\n  TRANSFER FAILED:", error.message || error)
    if (error.message?.includes("TRANSACTION_EXECUTION_ERROR")) {
      const match = error.message.match(/execution_error[\":\s]*(.*)/i)
      if (match) console.error("  Execution error:", match[1].slice(0, 500))
    }
    process.exit(1)
  }

  console.log("\n=== FULL E2E SUCCEEDED ===")
}

main().catch((e) => {
  console.error("Fatal:", e)
  process.exit(1)
})

