#!/usr/bin/env node
/**
 * Deploy a Falcon-512 account on Starknet and send a test transfer.
 *
 * Environment variables:
 *   CLASS_HASH        — declared FalconAccount class hash (required)
 *   FALCON_WASM_PATH  — path to Node.js WASM package (default: bin/.wasm-nodejs)
 *   RPC_URL           — JSON-RPC endpoint (default: http://localhost:5050/rpc)
 */

import { createRequire } from "module"
import { dirname, resolve } from "path"
import { fileURLToPath } from "url"
import {
  RpcProvider, Account, hash, stark, CallData, SignerInterface,
  transaction, EDAMode,
} from "../apps/demo/node_modules/starknet/dist/index.mjs"

const __dirname = dirname(fileURLToPath(import.meta.url))

// --- Config ---
const CLASS_HASH = process.env.CLASS_HASH
if (!CLASS_HASH) {
  console.error("ERROR: CLASS_HASH env var is required")
  process.exit(1)
}
const RPC_URL = process.env.RPC_URL || "http://localhost:5050/rpc"
const WASM_PATH = resolve(process.env.FALCON_WASM_PATH || `${__dirname}/.wasm-nodejs`)

const require = createRequire(import.meta.url)
const falcon = require(resolve(WASM_PATH, "falcon_rs.js"))

const provider = new RpcProvider({ nodeUrl: RPC_URL })

// --- Helpers ---

/** Deserialize 896-byte VK into 512 time-domain Int32Array coefficients */
function parsePublicKey(vkBytes) {
  const Q = 12289, N = 512, BITS = 14
  const coeffs = new Int32Array(N)
  const mask = (1 << BITS) - 1
  let bitBuffer = 0, bitsInBuffer = 0, byteIndex = 0
  for (let i = 0; i < N; i++) {
    while (bitsInBuffer < BITS) {
      bitBuffer |= vkBytes[byteIndex++] << bitsInBuffer
      bitsInBuffer += 8
    }
    const coeff = bitBuffer & mask
    bitBuffer >>= BITS
    bitsInBuffer -= BITS
    if (coeff >= Q) throw new Error(`Invalid VK coeff ${coeff} at ${i}`)
    coeffs[i] = coeff
  }
  return coeffs
}

/** Convert Int32Array to Uint16Array for pack_public_key_wasm */
function toUint16(arr) {
  const u16 = new Uint16Array(arr.length)
  for (let i = 0; i < arr.length; i++) u16[i] = arr[i]
  return u16
}

/** Fund an address via devnet JSON-RPC mint */
async function mintFunds(address, amount, unit) {
  const baseUrl = RPC_URL.replace(/\/rpc.*$/, "")
  const resp = await fetch(baseUrl, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      jsonrpc: "2.0", id: 1,
      method: "devnet_mint",
      params: { address, amount, unit },
    }),
  })
  if (!resp.ok) throw new Error(`Mint failed: ${resp.status} ${await resp.text()}`)
  const json = await resp.json()
  if (json.error) throw new Error(`Mint error: ${JSON.stringify(json.error)}`)
  return json.result
}

/** Get STRK balance of an address */
async function getBalance(address) {
  const STRK = "0x04718f5a0fc34cc1af16a1cdee98ffb20c31f5cd61d6ab07201858f4287c938d"
  const result = await provider.callContract({
    contractAddress: STRK,
    entrypoint: "balanceOf",
    calldata: [address],
  })
  return BigInt(result[0])
}

// --- Falcon Signer ---

const RESOURCE_BOUNDS = {
  l2_gas: { max_amount: 0x2FAF080n, max_price_per_unit: 0x174876E800n },
  l1_gas: { max_amount: 0x0n, max_price_per_unit: 0x174876E800n },
  l1_data_gas: { max_amount: 0x3000n, max_price_per_unit: 0x174876E800n },
}

class FalconSigner extends SignerInterface {
  constructor(sk, pkNtt) {
    super()
    this.sk = sk
    this.pkNtt = pkNtt
  }

  async getPubKey() { return "0x0" }
  async signMessage() { throw new Error("signMessage not implemented") }
  async signDeclareTransaction() { throw new Error("signDeclareTransaction not implemented") }

  async signTransaction(transactions, details) {
    const compiledCalldata = transaction.getExecuteCalldata(transactions, details.cairoVersion)
    const txHash = hash.calculateInvokeTransactionHash({
      ...details,
      senderAddress: details.walletAddress,
      compiledCalldata,
      version: details.version,
      nonceDataAvailabilityMode: details.nonceDataAvailabilityMode === "L1" ? EDAMode.L1 : EDAMode.L2,
      feeDataAvailabilityMode: details.feeDataAvailabilityMode === "L1" ? EDAMode.L1 : EDAMode.L2,
    })
    return this._sign(txHash)
  }

  async signDeployAccountTransaction(details) {
    const compiledConstructorCalldata = CallData.compile(details.constructorCalldata)
    const txHash = hash.calculateDeployAccountTransactionHash({
      ...details,
      salt: details.addressSalt,
      compiledConstructorCalldata,
      version: details.version,
      nonceDataAvailabilityMode: details.nonceDataAvailabilityMode === "L1" ? EDAMode.L1 : EDAMode.L2,
      feeDataAvailabilityMode: details.feeDataAvailabilityMode === "L1" ? EDAMode.L1 : EDAMode.L2,
    })
    return this._sign(txHash)
  }

  _sign(txHash) {
    console.log(`  Signing ${txHash.slice(0, 18)}...`)
    return falcon.sign_for_starknet(this.sk, txHash, this.pkNtt)
  }
}

// --- Main ---

async function main() {
  console.log("=== Falcon-512 E2E Deploy ===\n")
  console.log(`  RPC:        ${RPC_URL}`)
  console.log(`  ClassHash:  ${CLASS_HASH}`)
  console.log(`  WASM:       ${WASM_PATH}\n`)

  // 1. Keygen
  console.log("1. Generating keypair...")
  const seed = new Uint8Array(32)
  for (let i = 0; i < 32; i++) seed[i] = i + 1
  const { sk, vk } = falcon.keygen(seed)
  console.log(`   SK: ${sk.length} bytes, VK: ${vk.length} bytes`)

  // 2. NTT + pack public key
  console.log("2. NTT-transforming and packing public key...")
  const pkTime = parsePublicKey(vk)
  const pkNtt = new Int32Array(falcon.ntt_public_key(pkTime))
  const packedSlots = falcon.pack_public_key_wasm(toUint16(pkNtt))
  console.log(`   ${packedSlots.length} packed felt252 slots`)

  // 3. Compute address
  console.log("3. Computing deploy address...")
  const constructorCalldata = [...packedSlots]
  const salt = stark.randomAddress()
  const address = hash.calculateContractAddressFromHash(salt, CLASS_HASH, constructorCalldata, 0)
  console.log(`   Address: ${address}`)

  // 4. Fund
  console.log("4. Minting STRK...")
  await mintFunds(address, 10000000000000000000, "FRI")
  const balance = await getBalance(address)
  console.log(`   Balance: ${Number(balance) / 1e18} STRK`)

  // 5. Deploy
  console.log("5. Deploying account...")
  const signer = new FalconSigner(sk, pkNtt)
  const account = new Account({ provider, address, signer })

  const deployResult = await account.deployAccount(
    {
      classHash: CLASS_HASH,
      constructorCalldata,
      addressSalt: salt,
      contractAddress: address,
    },
    { resourceBounds: RESOURCE_BOUNDS },
  )
  console.log(`   Deploy tx: ${deployResult.transaction_hash}`)
  await provider.waitForTransaction(deployResult.transaction_hash)
  console.log("   Confirmed!")

  // 6. Transfer
  console.log("6. Sending STRK transfer...")
  const STRK_TOKEN = "0x04718f5a0fc34cc1af16a1cdee98ffb20c31f5cd61d6ab07201858f4287c938d"
  const recipient = "0x064b48806902a367c8598f4f95c305e8c1a1acba5f082d294a43793113115691"
  const transferAmount = 1000000000000000n

  const txResult = await account.execute(
    [{
      contractAddress: STRK_TOKEN,
      entrypoint: "transfer",
      calldata: CallData.compile({ recipient, amount: { low: transferAmount, high: 0n } }),
    }],
    { resourceBounds: RESOURCE_BOUNDS },
  )
  console.log(`   Transfer tx: ${txResult.transaction_hash}`)
  await provider.waitForTransaction(txResult.transaction_hash)

  const balanceAfter = await getBalance(address)
  console.log(`   Balance after: ${Number(balanceAfter) / 1e18} STRK`)

  console.log("\n=== E2E PASSED ===")
}

main().catch((e) => {
  console.error("\nFATAL:", e.message || e)
  process.exit(1)
})

import { Config, Effect, Layer } from "effect"
import { RpcProvider, Account, hash, stark } from "starknet"
import type { SignerInterface } from "starknet"
import {
  StarknetRpcError,
  AccountDeployError,
  DevnetFetchError,
  TransactionSubmitError,
} from "./errors"
import { TxHash, ContractAddress } from "./types"
import type { PackedPublicKey, DevnetAccount } from "./types"

/** STRK token contract address (same on mainnet and Sepolia) */
export const STRK_TOKEN_ADDRESS =
  "0x04718f5a0fc34cc1af16a1cdee98ffb20c31f5cd61d6ab07201858f4287c938d"

export function parsePrefundedAccounts(raw: unknown[]): DevnetAccount[] {
  return raw
    .filter((item): item is Record<string, string> =>
      typeof item === "object" && item !== null &&
      "address" in item && "private_key" in item
    )
    .map((item) => ({
      address: item.address,
      private_key: item.private_key,
      initial_balance: item.initial_balance ?? "0",
    }))
}

function makeService(rpcUrl: string, classHash: string) {
  const provider = new RpcProvider({ nodeUrl: rpcUrl })

  const computeDeployAddress = Effect.fn("Starknet.computeDeployAddress")(
    function* (packedPk: PackedPublicKey) {
      // PackedPolynomial512 is a flat struct (s0..s28), not an Array.
      // CallData.compile would add a length prefix; pass raw slots instead.
      const constructorCalldata = [...packedPk.slots]
      const salt = stark.randomAddress()
      const address = hash.calculateContractAddressFromHash(
        salt,
        classHash,
        constructorCalldata,
        0,
      )
      return {
        address: ContractAddress.make(address),
        salt,
      }
    },
  )

  const getBalance = Effect.fn("Starknet.getBalance")(
    function* (address: string) {
      return yield* Effect.tryPromise({
        try: async () => {
          const result = await provider.callContract({
            contractAddress: STRK_TOKEN_ADDRESS,
            entrypoint: "balanceOf",
            calldata: [address],
          })
          return BigInt(result[0])
        },
        catch: (error) =>
          new StarknetRpcError({ message: String(error), code: -1 }),
      })
    },
  )

  const deployAccount = Effect.fn("Starknet.deployAccount")(
    function* (
      packedPk: PackedPublicKey,
      signer: SignerInterface,
      salt: string,
    ) {
      // PackedPolynomial512 is a flat struct (s0..s28), not an Array.
      // CallData.compile would add a length prefix; pass raw slots instead.
      const constructorCalldata = [...packedPk.slots]
      const address = hash.calculateContractAddressFromHash(
        salt,
        classHash,
        constructorCalldata,
        0,
      )

      const account = new Account({ provider, address, signer })

      const result = yield* Effect.tryPromise({
        try: () =>
          account.deployAccount(
            {
              classHash,
              constructorCalldata,
              addressSalt: salt,
              contractAddress: address,
            },
            {
              // Falcon-512 verification is ~63K steps (~13.2M L2 gas).
              // Auto-estimation often fails for compute-heavy contracts,
              // so we set explicit resource bounds.
              resourceBounds: {
                l2_gas: { max_amount: 0x2FAF080n, max_price_per_unit: 0x174876E800n },
                l1_gas: { max_amount: 0x0n, max_price_per_unit: 0x174876E800n },
                l1_data_gas: { max_amount: 0x3000n, max_price_per_unit: 0x174876E800n },
              },
            },
          ),
        catch: (error) =>
          new AccountDeployError({ message: String(error) }),
      })

      yield* Effect.tryPromise({
        try: () => provider.waitForTransaction(result.transaction_hash),
        catch: (error) =>
          new AccountDeployError({
            message: `Tx failed: ${error}`,
            txHash: result.transaction_hash,
          }),
      })

      return {
        txHash: TxHash.make(result.transaction_hash),
        address: ContractAddress.make(result.contract_address),
      }
    },
  )

  const waitForTx = Effect.fn("Starknet.waitForTx")(
    function* (txHash: string) {
      yield* Effect.tryPromise({
        try: () => provider.waitForTransaction(txHash),
        catch: (error) =>
          new StarknetRpcError({ message: String(error), code: -1 }),
      })
    },
  )

  const fetchPrefundedAccounts = Effect.fn("Starknet.fetchPrefundedAccounts")(
    function* () {
      return yield* Effect.tryPromise({
        try: async () => {
          const baseUrl = rpcUrl.replace(/\/rpc.*$/, "").replace(/\/$/, "")
          const response = await fetch(baseUrl, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              jsonrpc: "2.0",
              id: 1,
              method: "devnet_getPredeployedAccounts",
              params: [],
            }),
          })
          if (!response.ok) {
            throw new Error(`HTTP ${response.status}`)
          }
          const json = await response.json()
          if (json.error) {
            throw new Error(json.error.message ?? JSON.stringify(json.error))
          }
          return parsePrefundedAccounts(json.result as unknown[])
        },
        catch: (error) =>
          new DevnetFetchError({ message: `Failed to fetch prefunded accounts: ${error}` }),
      })
    },
  )

  const sendTransaction = Effect.fn("Starknet.sendTransaction")(
    function* (
      accountAddress: string,
      signer: SignerInterface,
      recipient: string,
      amount: bigint,
    ) {
      const account = new Account({ provider, address: accountAddress, signer })
      return yield* Effect.tryPromise({
        try: async () => {
          const result = await account.execute([
            {
              contractAddress: STRK_TOKEN_ADDRESS,
              entrypoint: "transfer",
              calldata: [recipient, amount.toString(), "0"],
            },
          ])
          await provider.waitForTransaction(result.transaction_hash)
          return { txHash: TxHash.make(result.transaction_hash) }
        },
        catch: (error) =>
          new TransactionSubmitError({ message: String(error) }),
      })
    },
  )

  return {
    computeDeployAddress,
    getBalance,
    deployAccount,
    waitForTx,
    fetchPrefundedAccounts,
    sendTransaction,
    provider,
  }
}

// @ts-ignore — StarknetService.make() intentionally overrides the inherited Effect.Service.make() with a Layer factory
export class StarknetService extends Effect.Service<StarknetService>()(
  "StarknetService",
  {
    accessors: true,
    effect: Effect.gen(function* () {
      const rpcUrl = yield* Config.string("NEXT_PUBLIC_STARKNET_RPC_URL")
      return makeService(rpcUrl, "0x0")
    }),
  },
) {
  /**
   * Custom layer factory for runtime network switching.
   * Use this instead of Default when you need a specific rpcUrl and classHash
   * (e.g., switching between Sepolia and Mainnet at runtime).
   */
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  static make(rpcUrl: string, classHash: string): Layer.Layer<StarknetService> {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    return Layer.succeed(StarknetService, makeService(rpcUrl, classHash) as any)
  }
}
